const FLOWER_CSS = `
  @keyframes floatA { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-14px) rotate(12deg)} }
  @keyframes floatB { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-9px) rotate(-9deg)} }
  @keyframes floatC { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-18px) rotate(18deg)} }
`;

// ── Confirmation Modal ─────────────────────────────
function ConfirmModal({ message, subtext, onConfirm, onCancel, confirmLabel = 'Yes, Continue 🌸', icon = '🌸' }) {
  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(45,31,31,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999, padding: '1rem' }}>
      <div style={{ background: 'white', borderRadius: '24px', padding: '2.5rem', maxWidth: '400px', width: '100%', textAlign: 'center', boxShadow: '0 30px 60px rgba(45,31,31,0.3)', position: 'relative', overflow: 'hidden' }}>
        {/* Flower corners */}
        <div style={{ position: 'absolute', top: '12px', left: '16px', fontSize: '1.2rem', opacity: 0.2 }}>🌸</div>
        <div style={{ position: 'absolute', top: '12px', right: '16px', fontSize: '1.2rem', opacity: 0.2 }}>🌺</div>
        <div style={{ position: 'absolute', bottom: '12px', left: '16px', fontSize: '1rem', opacity: 0.15 }}>🌼</div>
        <div style={{ position: 'absolute', bottom: '12px', right: '16px', fontSize: '1rem', opacity: 0.15 }}>🌷</div>

        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>{icon}</div>
        <h2 style={{ color: '#2d1f1f', fontWeight: '700', fontSize: '1.3rem', marginBottom: '0.5rem', fontFamily: "'Cormorant Garamond', serif" }}>{message}</h2>
        <p style={{ color: '#a08880', fontSize: '0.88rem', marginBottom: '2rem', lineHeight: '1.6' }}>{subtext}</p>

        <div style={{ display: 'flex', gap: '12px' }}>
          <button onClick={onCancel} style={{ flex: 1, padding: '12px', background: '#f5e8e3', color: '#a08880', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: '600', fontSize: '0.88rem', fontFamily: "'DM Sans', sans-serif" }}>
            Cancel
          </button>
          <button onClick={onConfirm} style={{ flex: 2, padding: '12px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: '700', fontSize: '0.88rem', fontFamily: "'DM Sans', sans-serif", boxShadow: '0 4px 14px rgba(201,169,154,0.4)' }}>
            {confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}

function Login() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleSubmitClick = (e) => {
    e.preventDefault();
    if (!form.email || !form.password) { setError('Please fill in all fields'); return; }
    setError('');
    setShowConfirm(true);
  };

  const handleConfirmLogin = async () => {
    setShowConfirm(false);
    setLoading(true);
    try {
      const res = await API.post('/auth/login', form);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      if (res.data.user.role === 'admin') navigate('/admin');
      else navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #fdf6f3 0%, #f9ede8 50%, #f5e0d8 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem', fontFamily: "'DM Sans', sans-serif", position: 'relative', overflow: 'hidden' }}>
      <style>{FLOWER_CSS}</style>

      {/* BG flowers */}
      {[{f:'🌸',t:'5%',l:'3%',a:'floatA',d:'4s',op:0.18},{f:'🌺',t:'10%',l:'90%',a:'floatB',d:'5s',op:0.15},{f:'🌼',t:'80%',l:'2%',a:'floatC',d:'6s',op:0.12},{f:'🌷',t:'85%',l:'92%',a:'floatA',d:'4.5s',op:0.14},{f:'💮',t:'50%',l:'1%',a:'floatB',d:'3.8s',op:0.10},{f:'🌸',t:'45%',l:'95%',a:'floatC',d:'5.5s',op:0.11}].map((fl,i)=>(
        <span key={i} style={{position:'absolute',top:fl.t,left:fl.l,fontSize:'1.8rem',opacity:fl.op,animation:`${fl.a} ${fl.d} ease-in-out infinite`,animationDelay:`${i*0.4}s`,pointerEvents:'none'}}>{fl.f}</span>
      ))}

      {showConfirm && (
        <ConfirmModal
          icon="🌸"
          message="Ready to Sign In?"
          subtext={`Welcome back! You're signing in as ${form.email}`}
          confirmLabel="Yes, Sign In 🌸"
          onConfirm={handleConfirmLogin}
          onCancel={() => setShowConfirm(false)}
        />
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '880px', width: '100%', borderRadius: '28px', overflow: 'hidden', boxShadow: '0 30px 80px rgba(201,169,154,0.3)', border: '1px solid #f0ddd7', position: 'relative', zIndex: 1 }}>

        {/* Left */}
        <div style={{ background: 'linear-gradient(150deg, #c9a99a 0%, #b8887a 50%, #a0706a 100%)', padding: '3rem 2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', top: '-50px', right: '-50px', width: '180px', height: '180px', borderRadius: '50%', background: 'rgba(255,255,255,0.1)' }} />
          {/* Panel flowers */}
          {['🌸','🌺','🌼','🌷'].map((f,i)=>(
            <span key={i} style={{position:'absolute',fontSize:'1.3rem',opacity:0.2,top:`${15+i*20}%`,left:`${5+i*5}%`,animation:`floatA ${3.5+i*0.5}s ease-in-out infinite`,animationDelay:`${i*0.3}s`,pointerEvents:'none'}}>{f}</span>
          ))}
          <div style={{ position: 'relative' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🌸</div>
            <h2 style={{ color: 'white', fontSize: '2rem', fontWeight: '700', marginBottom: '1rem', lineHeight: '1.3', fontFamily: "'Cormorant Garamond', serif" }}>Welcome Back to EventHub!</h2>
            <p style={{ color: 'rgba(255,255,255,0.75)', lineHeight: '1.7', marginBottom: '2rem', fontSize: '0.88rem' }}>Discover beautiful events, book tickets effortlessly.</p>
            {[{icon:'🎭',text:'Explore curated events'},{icon:'🎫',text:'Instant ticket booking'},{icon:'💝',text:'Secure & easy payments'},{icon:'📅',text:'Track all your bookings'}].map((f,i)=>(
              <div key={i} style={{display:'flex',alignItems:'center',gap:'12px',marginBottom:'12px'}}>
                <div style={{width:'34px',height:'34px',background:'rgba(255,255,255,0.2)',borderRadius:'9px',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'0.9rem',flexShrink:0}}>{f.icon}</div>
                <span style={{color:'rgba(255,255,255,0.88)',fontSize:'0.83rem',fontWeight:'500'}}>{f.text}</span>
              </div>
            ))}
            <div style={{ marginTop: '2rem', background: 'rgba(255,255,255,0.15)', borderRadius: '12px', padding: '12px 16px' }}>
              <p style={{ color: 'white', fontSize: '0.8rem', margin: 0 }}>👑 <strong>Admin?</strong> Login with admin email to access the admin panel automatically.</p>
            </div>
          </div>
        </div>

        {/* Right */}
        <div style={{ background: '#fffaf8', padding: '3rem 2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', bottom: '10px', right: '14px', fontSize: '1.4rem', opacity: 0.12, pointerEvents: 'none' }}>🌸</div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '2rem' }}>
            <div style={{ width: '34px', height: '34px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '9px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem' }}>🌸</div>
            <span style={{ fontWeight: '700', fontSize: '1.1rem', color: '#2d1f1f', fontFamily: "'Cormorant Garamond', serif" }}>Event<span style={{ color: '#c9a99a' }}>Hub</span></span>
          </div>

          <h1 style={{ color: '#2d1f1f', fontSize: '1.7rem', fontWeight: '700', marginBottom: '0.3rem', fontFamily: "'Cormorant Garamond', serif" }}>Sign In</h1>
          <p style={{ color: '#a08880', fontSize: '0.84rem', marginBottom: '1.8rem' }}>Welcome back! 🌷</p>

          {error && <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '11px 14px', borderRadius: '10px', marginBottom: '1.4rem', fontSize: '0.83rem' }}>⚠️ {error}</div>}

          <form onSubmit={handleSubmitClick}>
            {[{label:'Email Address',name:'email',type:'email',icon:'✉️',placeholder:'you@example.com'},{label:'Password',name:'password',type:'password',icon:'🔑',placeholder:'Your password'}].map(field=>(
              <div key={field.name} style={{marginBottom:'1.1rem'}}>
                <label style={{display:'block',color:'#6b5a55',fontSize:'0.76rem',fontWeight:'600',marginBottom:'7px'}}>{field.label}</label>
                <div style={{position:'relative'}}>
                  <span style={{position:'absolute',left:'13px',top:'50%',transform:'translateY(-50%)',fontSize:'0.9rem'}}>{field.icon}</span>
                  <input type={field.type} name={field.name} value={form[field.name]}
                    onChange={e=>setForm({...form,[e.target.name]:e.target.value})}
                    required placeholder={field.placeholder}
                    style={{width:'100%',padding:'12px 13px 12px 42px',background:'white',border:'1.5px solid #f0ddd7',borderRadius:'11px',color:'#2d1f1f',fontSize:'0.88rem',outline:'none',boxSizing:'border-box'}}
                    onFocus={e=>e.target.style.borderColor='#c9a99a'}
                    onBlur={e=>e.target.style.borderColor='#f0ddd7'} />
                </div>
              </div>
            ))}
            <button type="submit" disabled={loading} style={{width:'100%',padding:'13px',background:'linear-gradient(135deg, #c9a99a, #b8887a)',color:'white',border:'none',borderRadius:'11px',fontWeight:'600',fontSize:'0.92rem',cursor:'pointer',marginTop:'0.5rem',boxShadow:'0 6px 20px rgba(201,169,154,0.4)',opacity:loading?0.7:1,fontFamily:"'DM Sans', sans-serif"}}>
              {loading ? '✨ Signing in...' : '🌸 Sign In'}
            </button>
          </form>

          <p style={{ marginTop: '1.4rem', textAlign: 'center', color: '#a08880', fontSize: '0.83rem' }}>
            Don't have an account?{' '}
            <Link to="/register" style={{ color: '#c9a99a', fontWeight: '700', textDecoration: 'none' }}>Create one →</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export { ConfirmModal };
export default Login;
